function openReturnModal() {
    let html = `
        <div class="form-group">
            <label>${t('client')}:</label>
            <select id="return-client">
                <option value="">-- ${t('select_client')} --</option>
                ${(state.clients || []).map(c => `<option value="${c.id}">${c.name}</option>`).join('')}
            </select>
        </div>
        <div class="form-group">
            <label>${t('product')}:</label>
            <select id="return-product">
                ${(typeof PRODUCTS !== "undefined" ? PRODUCTS : []).map(p => `<option value="${p.id}">${p.name}</option>`).join('')}
            </select>
        </div>
        <div class="form-group">
            <label>${t('quantity')}:</label>
            <input type="number" id="return-quantity" min="1" value="1">
        </div>
        <div class="form-group">
            <label>${t('reason')}:</label>
            <textarea id="return-reason" placeholder="${t('enter_reason')}"></textarea>
        </div>
        <div class="form-group">
            <label>${t('date')}:</label>
            <input type="date" id="return-date" value="${new Date().toISOString().split('T')[0]}">
        </div>
        <button type="button" class="btn btn-primary" onclick="addReturn()" style="width:100%;">${t('new_return')}</button>
    `;
    openModal(t('new_return'), html);
}

function addReturn() {
    // Bug #75: DOM null-checks + state.returns/stock guards + logActivity guard
    const cEl = document.getElementById('return-client');
    const pEl = document.getElementById('return-product');
    const qEl = document.getElementById('return-quantity');
    const rEl = document.getElementById('return-reason');
    const dEl = document.getElementById('return-date');
    if (!pEl || !qEl) return;
    const clientId = cEl ? cEl.value : '';
    const productId = pEl.value;
    const quantity = parseInt(qEl.value) || 0;
    const reason = rEl ? rEl.value : '';
    const date = dEl ? dEl.value : new Date().toISOString().split('T')[0];

    if (quantity <= 0) return;

    if (!state.returns) state.returns = [];
    (state.returns = state.returns || []).push({ id: Date.now(), clientId, productId, quantity, reason, date });

    // Restore stock
    if (!state.stock) state.stock = {};
    (state.stock || {})[productId] = ((state.stock || {})[productId] || 0) + quantity;

    const product = getProduct(productId);
    if (typeof logActivity === 'function') logActivity('return', 'Kthim: ' + (product ? product.name : productId) + ' x' + quantity, 'returns');
    saveState();
    closeModal();
    refreshReturns();
    refreshAll();
}

function deleteReturn(index) {
    // Bug #76: state.returns bounds + state.stock guard
    modalConfirm('Fshi këtë kthim?', function() {
    if (!state.returns || !state.returns[index]) return;
    var ret = state.returns[index];
    if (!ret) { if (typeof showToast === "function") showToast("Të dhënat nuk u gjetën", "warning"); return; }
    if (!state.stock) state.stock = {};
    state.stock[ret.productId] = Math.max(0, (state.stock[ret.productId] || 0) - (ret.quantity || 0));
    (state.returns = state.returns || []).splice(index, 1);
    saveState();
    refreshReturns();
    });
    refreshAll();
}

function refreshReturns() {
    // Bug #169: tbody + state.returns/clients + product null-safe
    const tbody = document.getElementById('returns-body');
    if (!tbody) return;
    tbody.innerHTML = '';
    const returns = state.returns || [];
    [...returns].reverse().forEach((r, i) => {
        if (!r) return;
        const realIndex = returns.length - 1 - i;
        const product = getProduct(r.productId);
        const client = (state.clients || []).find(c => c && c.id === r.clientId);
        tbody.innerHTML += `
            <tr>
                <td>${r.date || '-'}</td>
                <td>${(client && client.name) ? client.name : '-'}</td>
                <td>${(product && product.name) ? product.name : '-'}</td>
                <td>${r.quantity || 0}</td>
                <td>${r.reason || '-'}</td>
                <td>
                    <button type="button" class="btn btn-sm btn-danger" onclick="deleteReturn(${realIndex})" aria-label="Delete return"><i class="fas fa-trash" aria-hidden="true"></i></button>
                </td>
            </tr>
        `;
    });
}

