// ===================== FEATURE 14: SMART STOCK DEPLETION =====================
function calcStockDepletionDays(productId) {
    const currentStock = (state.stock || {})[productId] || 0;
    if (currentStock <= 0) return 0;

    // Calculate average daily sales from last 30 days
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    const thirtyDaysAgoStr = thirtyDaysAgo.toISOString().split('T')[0];

    const recentSales = (state.sales || []).filter(s => s && s.productId === productId && s.date >= thirtyDaysAgoStr);
    const totalSold = recentSales.reduce((sum, s) => sum + (s.quantity || 0), 0);
    const avgDailySales = totalSold / 30;

    if (avgDailySales <= 0) return null; // No sales data
    return Math.round(currentStock / avgDailySales);
}

// ===================== FEATURE 12: KEYBOARD SHORTCUTS =====================
function initKeyboardShortcuts() {
    document.addEventListener('keydown', function(e) {
        // Q: ESC must work even from inside inputs/textareas — users
        // press it to close a modal while still inside a form field.
        if (e.key === 'Escape') {
            // Try every overlay close in priority order. Each function
            // is null-safe (already checks for the element existing).
            try {
                var anyClosed = false;
                // Side panel (highest priority — usually opens over modal)
                var sp = document.getElementById('side-panel');
                if (sp && !sp.classList.contains('hidden')) {
                    if (typeof closeSidePanel === 'function') {
                        closeSidePanel(); anyClosed = true;
                    }
                }
                // Invoice modal
                var im = document.getElementById('invoice-modal');
                if (!anyClosed && im && !im.classList.contains('hidden')) {
                    if (typeof closeInvoiceModal === 'function') {
                        closeInvoiceModal(); anyClosed = true;
                    }
                }
                // Generic modal
                var m = document.getElementById('modal');
                if (!anyClosed && m && !m.classList.contains('hidden')) {
                    if (typeof closeModal === 'function') {
                        closeModal(); anyClosed = true;
                    }
                }
                if (anyClosed) {
                    e.preventDefault();
                    return;
                }
            } catch (err) { console.warn('ESC handler:', err); }
            // Fall through to other ESC consumers (search, palette, etc.)
        }

        // Don't trigger shortcuts when typing in inputs
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.tagName === 'SELECT') return;

        // Escape: close modal (legacy fallback — kept for safety)
        if (e.key === 'Escape') {
            closeModal();
            return;
        }

        // N: new sale
        if (e.key === 'n' || e.key === 'N') {
            e.preventDefault();
            openSaleModal();
            return;
        }

        // F: Faton payment
        if (e.key === 'f' || e.key === 'F') {
            e.preventDefault();
            openFatonPaymentModal();
            return;
        }

        // S: add stock
        if (e.key === 's' || e.key === 'S') {
            e.preventDefault();
            openStockModal();
            return;
        }

        // Ctrl+E: export
        if (e.ctrlKey && (e.key === 'e' || e.key === 'E')) {
            e.preventDefault();
            exportCSV();
            return;
        }

        // ?: show keyboard shortcuts help
        if (e.key === '?') {
            e.preventDefault();
            showKeyboardShortcutsHelp();
            return;
        }
    });
}

function showKeyboardShortcutsHelp() {
    const html = `
        <div style="line-height:2;">
            <p><kbd style="background:var(--bg-primary);padding:2px 8px;border-radius:4px;border:1px solid var(--border);">N</kbd> - Shitje e re</p>
            <p><kbd style="background:var(--bg-primary);padding:2px 8px;border-radius:4px;border:1px solid var(--border);">F</kbd> - Pagesa Fatonit</p>
            <p><kbd style="background:var(--bg-primary);padding:2px 8px;border-radius:4px;border:1px solid var(--border);">S</kbd> - Shto stok</p>
            <p><kbd style="background:var(--bg-primary);padding:2px 8px;border-radius:4px;border:1px solid var(--border);">Ctrl+E</kbd> - Eksporto CSV</p>
            <p><kbd style="background:var(--bg-primary);padding:2px 8px;border-radius:4px;border:1px solid var(--border);">Escape</kbd> - Mbyll modalin</p>
            <p><kbd style="background:var(--bg-primary);padding:2px 8px;border-radius:4px;border:1px solid var(--border);">?</kbd> - Ndihme per shortcutet</p>
        </div>
    `;
    openModal('Shortcutet e tastjeres', html);
}

