// ===================== FEATURE 25: ORHAN REPORT =====================
function generateOrhanReport() {
    const dateFrom = document.getElementById('orhan-date-from') ? (document.getElementById('orhan-date-from') || {}).value : '';
    const dateTo = document.getElementById('orhan-date-to') ? (document.getElementById('orhan-date-to') || {}).value : '';

    // Bug #99: state.sales/expenses guards + NaN fallbacks
    let sales = (state.sales || []);
    if (dateFrom) sales = sales.filter(s => s.date >= dateFrom);
    if (dateTo) sales = sales.filter(s => s.date <= dateTo);

    const totalProfit = sales.reduce((sum, s) => sum + (s.profit || 0), 0);
    let filteredExpenses = (state.expenses || []);
    if (dateFrom) filteredExpenses = filteredExpenses.filter(e => e.date >= dateFrom);
    if (dateTo) filteredExpenses = filteredExpenses.filter(e => e.date <= dateTo);
    const totalExpenses = filteredExpenses.reduce((sum, e) => sum + (e.amount || 0), 0);
    const sharedExpenses = filteredExpenses.filter(e => e.shared).reduce((sum, e) => sum + (e.amount || 0), 0);
    const personalExpenses = totalExpenses - sharedExpenses;
    const sharedExpensePerPerson = Math.round(sharedExpenses / 2);

    const netProfit = totalProfit - totalExpenses;
    const orhanShare = calcPartnerShare(netProfit);
    const orhanSharedExpense = sharedExpensePerPerson;

    const cashProfit = sales.filter(s => (s.paymentType || 'cash') === 'cash').reduce((sum, s) => sum + (s.profit || 0), 0);
    const invoiceProfit = sales.filter(s => s.paymentType === 'invoice_60').reduce((sum, s) => sum + (s.profit || 0), 0);
    const collectedProfit = calcFatonProfitCollected();

    let html = `
        <div class="form-group" style="display:flex;gap:10px;margin-bottom:15px;">
            <div>
                <label>Nga:</label>
                <input type="date" id="orhan-date-from" value="${dateFrom}" onchange="generateOrhanReport()">
            </div>
            <div>
                <label>Deri:</label>
                <input type="date" id="orhan-date-to" value="${dateTo}" onchange="generateOrhanReport()">
            </div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">
            <div class="stat-card"><div><h3>Fitimi total</h3><p>${totalProfit} den</p></div></div>
            <div class="stat-card"><div><h3>Shpenzimet totale</h3><p>${totalExpenses} den</p></div></div>
            <div class="stat-card"><div><h3>Fitimi neto</h3><p>${netProfit} den</p></div></div>
            <div class="stat-card" style="border-left:4px solid var(--accent)"><div><h3>Pjesa e Orhanit</h3><p style="font-size:1.2em;font-weight:bold;">${orhanShare} den</p></div></div>
            <div class="stat-card"><div><h3>Fitimi cash</h3><p>${cashProfit} den</p></div></div>
            <div class="stat-card"><div><h3>Fitimi faturash</h3><p>${invoiceProfit} den</p></div></div>
            <div class="stat-card"><div><h3>Fitimi i mbledhur (fatura)</h3><p>${collectedProfit} den</p></div></div>
            <div class="stat-card"><div><h3>Shpenzime te perbashketa</h3><p>${sharedExpenses} den (${sharedExpensePerPerson} per person)</p></div></div>
        </div>
        <div style="margin-top:15px;">
            <button type="button" class="btn btn-primary" onclick="exportOrhanReport()"><i class="fas fa-download" aria-hidden="true"></i> Eksporto raportin</button>
        </div>
    `;
    openModal('Raporti i Orhanit', html);
}

function exportOrhanReport() {
    // Bug #18: Guard state arrays (mungesë mund të shkaktojë TypeError)
    // dhe (s.profit || 0) / (e.amount || 0) që rekorde të vjetra pa këto fusha të mos bëhen NaN
    const totalProfit = (state.sales || []).reduce((sum, s) => sum + (s.profit || 0), 0);
    const totalExpenses = (state.expenses || []).reduce((sum, e) => sum + (e.amount || 0), 0);
    const netProfit = totalProfit - totalExpenses;
    const partnerShare = calcPartnerShare(netProfit) || 0;
    const fatonDebt = calcFatonDebt() || 0;
    // Bug #18: fallback për emrin e partnerit (shmang "Pjesa e undefined")
    const partnerName = state.partnerName || 'Partneri';

    let text = '=== RAPORTI I ORHANIT ===\n';
    // Bug #18: data në format shqip
    text += `Data: ${new Date().toLocaleDateString('sq-AL')}\n\n`;
    text += `Fitimi total: ${totalProfit} den\n`;
    text += `Shpenzimet: ${totalExpenses} den\n`;
    text += `Fitimi neto: ${netProfit} den\n`;
    text += `Pjesa e ${partnerName}: ${partnerShare} den\n`;
    text += `Borxhi ndaj Fatonit: ${fatonDebt} den\n`;

    downloadFile('orhan-raport.txt', text, 'text/plain;charset=utf-8');
    showToast('Raporti i Orhanit u eksportua', 'success');
}

// ===================== POPULATE CLIENT SELECTS WITH PINNED FIRST (Feature 24) =====================
function getClientOptionsHtml(selectedId) {
    // Bug #100: state.clients guard
    const pinned = state.pinnedClients || [];
    const sorted = [...(state.clients || [])].sort((a, b) => {
        const aPin = pinned.includes(a.id) ? 0 : 1;
        const bPin = pinned.includes(b.id) ? 0 : 1;
        return aPin - bPin;
    });
    return sorted.map(c => {
        const pin = pinned.includes(c.id) ? '* ' : '';
        return `<option value="${c.id}" ${selectedId === c.id ? 'selected' : ''}>${pin}${c.name}</option>`;
    }).join('');
}

// ===================== FEATURE 1: PRODUCT MANAGEMENT =====================
function openProductModal(editId) {
    const isEdit = editId !== undefined;
    const product = isEdit ? (typeof PRODUCTS !== "undefined" ? PRODUCTS : []).find(p => p.id === editId) : null;

    let html = `
        <div class="form-group">
            <label>Product Name:</label>
            <input type="text" id="product-name" value="${product ? product.name : ''}" required>
        </div>
        <div class="form-group">
            <label>Weight/Size:</label>
            <input type="text" id="product-weight" value="${product ? product.weight : ''}" placeholder="e.g., 500g, 1kg">
        </div>
        <div class="form-group">
            <label>Buy Price (den):</label>
            <input type="number" id="product-buy-price" min="0" value="${product ? product.buyPrice : 0}">
        </div>
        <div class="form-group">
            <label>Sell Price (den):</label>
            <input type="number" id="product-sell-price" min="0" value="${product ? product.sellPrice : 0}">
        </div>
        <button type="button" class="btn btn-primary" onclick="${isEdit ? `updateProduct('${_oa(editId)}')` : 'addProduct()'}" style="width:100%;">
            ${isEdit ? 'Update Product' : 'Add Product'}
        </button>
        ${isEdit ? `<button type="button" class="btn btn-danger" onclick="deleteProduct('${_oa(editId)}')" style="width:100%; margin-top:10px;">Delete Product</button>` : ''}
    `;
    openModal(isEdit ? 'Edit Product' : 'Add Product', html);
}

function addProduct() {
    // Bug #95: DOM null-checks + state.stock guard + showToast/logActivity guards
    const nEl = document.getElementById('product-name');
    const wEl = document.getElementById('product-weight');
    const bEl = document.getElementById('product-buy-price');
    const sEl = document.getElementById('product-sell-price');
    if (!nEl) return;
    const name = (nEl.value || '').trim();
    const weight = wEl ? (wEl.value || '').trim() : '';
    const buyPrice = bEl ? (parseFloat(bEl.value) || 0) : 0;
    const sellPrice = sEl ? (parseFloat(sEl.value) || 0) : 0;

    if (!name) {
        if (typeof showToast === 'function') showToast('Product name is required', 'error');
        return;
    }

    const id = 'custom_' + Date.now();
    const newProduct = { id, name, weight, buyPrice, sellPrice };
    if (typeof PRODUCTS === 'undefined') return;
    PRODUCTS.push(newProduct);
    state.customProducts = [...PRODUCTS];
    if (!state.stock) state.stock = {};
    (state.stock || {})[id] = 0;

    saveState();
    closeModal();
    refreshProducts();
    populateProductSelects();
    if (typeof showToast === 'function') showToast('Product added successfully', 'success');
    if (typeof logActivity === 'function') logActivity('Product Added', `Added product: ${name}`);
}

function updateProduct(id) {
    // Bug #96: DOM null-checks + PRODUCTS guard + showToast/logActivity guards
    if (typeof PRODUCTS === 'undefined') return;
    const nEl = document.getElementById('product-name');
    const wEl = document.getElementById('product-weight');
    const bEl = document.getElementById('product-buy-price');
    const sEl = document.getElementById('product-sell-price');
    if (!nEl) return;
    const name = (nEl.value || '').trim();
    const weight = wEl ? (wEl.value || '').trim() : '';
    const buyPrice = bEl ? (parseFloat(bEl.value) || 0) : 0;
    const sellPrice = sEl ? (parseFloat(sEl.value) || 0) : 0;

    if (!name) {
        if (typeof showToast === 'function') showToast('Product name is required', 'error');
        return;
    }

    const productIndex = PRODUCTS.findIndex(p => p.id === id);
    if (productIndex === -1) return;

    PRODUCTS[productIndex] = { id, name, weight, buyPrice, sellPrice };
    state.customProducts = [...PRODUCTS];

    saveState();
    closeModal();
    refreshProducts();
    populateProductSelects();
    if (typeof showToast === 'function') showToast('Product updated successfully', 'success');
    if (typeof logActivity === 'function') logActivity('Product Updated', `Updated product: ${name}`);
}

function deleteProduct(id) {
    // Bug #97: state.sales/stock guards + PRODUCTS guard + showToast/logActivity guards
    modalConfirm('Fshi këtë produkt? Kjo nuk mund të kthehet!', function() {
        if (typeof PRODUCTS === 'undefined') return;
        var usedInSales = (state.sales || []).some(function(s) { return s.productId === id; });
        if (usedInSales) {
            if (typeof showToast === 'function') showToast('Nuk mund të fshihet: produkti përdoret në historinë e shitjeve', 'error');
            return;
        }
        var productIndex = PRODUCTS.findIndex(function(p) { return p.id === id; });
        if (productIndex === -1) return;
        var productName = PRODUCTS[productIndex].name;
        PRODUCTS.splice(productIndex, 1);
        state.customProducts = PRODUCTS.slice();
        if (state.stock) delete (state.stock || {})[id];
        saveState();
        closeModal();
        refreshProducts();
        populateProductSelects();
        if (typeof showToast === 'function') showToast('Produkti u fshi!', 'success');
        if (typeof logActivity === 'function') logActivity('Product Deleted', 'Deleted product: ' + productName);
    });
}

function refreshProducts() {
    const container = document.getElementById('products-list');
    if (!container) return;

    let html = '<h3>Product Management</h3>';
    html += '<button type="button" class="btn btn-primary" onclick="openProductModal()" style="margin-bottom:15px;">Add New Product</button>';
    html += '<table class="data-table"><thead><tr><th>Name</th><th>Weight</th><th>Buy Price</th><th>Sell Price</th><th>Margin</th><th>Actions</th></tr></thead><tbody>';

    // Bug #98: PRODUCTS guard + field fallbacks
    (typeof PRODUCTS !== 'undefined' && PRODUCTS ? PRODUCTS : []).forEach(p => {
        const buyPrice = p.buyPrice || 0;
        const sellPrice = p.sellPrice || 0;
        const margin = sellPrice - buyPrice;
        const marginPct = buyPrice > 0 ? ((margin / buyPrice) * 100).toFixed(1) : 0;
        html += `
            <tr>
                <td>${p.name || '-'}</td>
                <td>${p.weight || '-'}</td>
                <td>${buyPrice} den</td>
                <td>${sellPrice} den</td>
                <td>${margin} den (${marginPct}%)</td>
                <td>
                    <button type="button" class="btn btn-sm" onclick="openProductModal('${_oa(p.id)}')">Edit</button>
                </td>
            </tr>
        `;
    });

    html += '</tbody></table>';
    container.innerHTML = html;
}

