    const rows = (state.contacts || []).map(c => [
        c.name || '-',
        c.phone || '-',
        c.email || '-',                          // email i shtuar (kishte munguar fare)
        c.role || '-',
        c.note || c.notes || '-'                 // fusha reale: note (njëjës)
    ]);
