    // Section headers
    h += '.section-hdr { font-size: 7.5pt; text-transform: uppercase; letter-spacing: 2.5px; color: ' + accent + '; font-weight: bold; margin-bottom: 8px; padding-bottom: 4px; border-bottom: 2px solid ' + accent + '; display: inline-block; }';
