        var headers = [['Data', 'Shuma', 'Metoda', 'Nënshkrim', 'Shënim']];
        var rows = payments.map(function(p) {
            return [p.date, p.amount + ' den', p.method === 'bank' ? 'Bankë' : 'Cash', p.signature ? 'Po' : '—', p.note || '-'];
        });
